1	package com.coding.assistant.config;
2	
3	import org.neo4j.driver.AuthTokens;
4	import org.neo4j.driver.Driver;
5	import org.neo4j.driver.GraphDatabase;
6	import org.springframework.beans.factory.annotation.Value;
7	import org.springframework.context.annotation.Bean;
8	import org.springframework.context.annotation.Configuration;
9	
10	@Configuration
11	public class Neo4jConfig {
12	
13	    @Value("${neo4j.uri}")
14	    private String uri;
15	
16	    @Value("${neo4j.username}")
17	    private String username;
18	
19	    @Value("${neo4j.password}")
20	    private String password;
21	
22	    @Bean
23	    public Driver neo4jDriver() {
24	        return GraphDatabase.driver(uri, AuthTokens.basic(username, password));
25	    }
26	}
